sql:
SELECT users.username, access_logs.access_date
FROM users
LEFT JOIN access_logs ON users.user_id = access_logs.user_id;

SELECT problem_name, equation
FROM ode_problems
WHERE author = 'Jane Smith';

external_knowledge:
- "sailors still navigating the seas" metaphorically refers to active users (is_active = 1) who have engaged with the problem;
- "problem number one" represents the problem with problem_id = 1;
- "named in order from the last to the first wave" represents sorting the user names in descending order.

sql:
SELECT COUNT(*) 
FROM access_logs 
WHERE user_id = 0 AND problem_id = 1;

SELECT problem_name, equation, initial_condition, exact_solution, author, created_at, updated_at, description, tags
FROM ode_problems
WHERE problem_id = 1;

SELECT problem_name
FROM ode_problems
WHERE tags LIKE '%decay%';

SELECT DISTINCT LOWER(op.problem_name) AS problem_name
FROM ode_problems AS op
JOIN access_logs AS al ON op.problem_id = al.problem_id;

SELECT author, COUNT(problem_id) AS total_problems
FROM ode_problems
GROUP BY author;

SELECT problem_name
FROM ode_problems
WHERE author = 'John Doe';

external_knowledge:
- "differential equation scenarios" refers to ODE problems;
- "numerical approaches" represents the numerical methods used to approximate solutions;
- "typical inaccuracies" indicates the average error in approximations.

sql:
SELECT problem_name, equation
FROM ode_problems
ORDER BY problem_id DESC;
